 1	import type { FC, ReactNode } from 'react';
 2	import { TableCell } from 'src/modules/Providers/utils/components/TableCell/TableCell';
 3	import { calculateCidrNotation } from 'src/modules/Providers/views/details/tabs/Hosts/utils/helpers/calculateCidrNotation';
 4	import { determineHostStatus } from 'src/modules/Providers/views/details/tabs/Hosts/utils/helpers/determineHostStatus';
 5	import { useForkliftTranslation } from 'src/utils/i18n';
 6	
 7	import { Button, ButtonVariant, HelperText, HelperTextItem, Popover } from '@patternfly/react-core';
 8	import {
 9	  CheckCircleIcon,
10	  ExclamationCircleIcon,
11	  ExclamationTriangleIcon,
12	} from '@patternfly/react-icons';
13	
14	import type { HostCellProps } from './utils/types';
15	
16	const statusIcons: Record<string, ReactNode> = {
17	  error: <ExclamationCircleIcon color="#C9190B" />,
18	  ready: <CheckCircleIcon color="#3E8635" />,
19	  running: <ExclamationTriangleIcon color="#F0AB00" />,
20	};
21	
22	// Define cell renderer for 'network'
23	const NetworkCellRenderer: FC<HostCellProps> = (props) => {
24	  const { t } = useForkliftTranslation();
25	
26	  const host = props?.data?.host;
27	  const name = props?.data?.networkAdapter?.name;
28	  const ip = props?.data?.networkAdapter?.ipAddress;
29	  const subnetMask = props?.data?.networkAdapter?.subnetMask;
30	
31	  const cidr = ip && subnetMask ? calculateCidrNotation(ip, subnetMask) : '';
32	
33	  const hostStatus = determineHostStatus(host);
34	  const statusIcon = statusIcons[hostStatus.status.toLowerCase()];
35	
36	  const defaultNetworkLabel = (
37	    <HelperText>
38	      <HelperTextItem variant="indeterminate">{t('Default network')}</HelperTextItem>
39	    </HelperText>
40	  );
41	
42	  let cellContent = (
43	    <>
44	      {statusIcon} {name ? `${name} - ${cidr}` : defaultNetworkLabel}
45	    </>
46	  );
47	
48	  if (hostStatus.status === 'Running' || hostStatus.status === 'Error') {
49	    cellContent = (
50	      <Popover
51	        showClose={false}
52	        aria-label="Host status details"
53	        headerContent={
54	          <div>
55	            {statusIcon} {hostStatus.status}
56	          </div>
57	        }
58	        bodyContent={<div>{hostStatus.message}</div>}
59	      >
60	        <Button
61	          variant={ButtonVariant.link}
62	          isInline
63	          data-testid="popover-status-button-host-network"
64	        >
65	          {cellContent}
66	        </Button>
67	      </Popover>
68	    );
69	  }
70	
71	  return <TableCell>{cellContent}</TableCell>;
72	};
73	
74	export default NetworkCellRenderer;

